import crypto from "node:crypto";
import { getPool } from "../db/pool.js";
import { resolveSemanticField } from "./semanticResolver.js";
import { fetchCurrentValueFromAuthority, recordConsumedProof } from "./stateAuthorityClient.js";

const STATEFUL_TYPES = new Set([
  "CumulativeLimitConstraint",
  "UsageLimitConstraint",
]);

export function isStatefulConstraint(constraint) {
  return STATEFUL_TYPES.has(constraint?.type);
}

function stableStringify(value) {
  if (value === null || typeof value !== "object") return JSON.stringify(value);
  if (Array.isArray(value)) return `[${value.map((item) => stableStringify(item)).join(",")}]`;
  return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableStringify(value[key])}`).join(",")}}`;
}

function sha256(value) {
  return crypto.createHash("sha256").update(value).digest("hex");
}

function windowForPeriod(period = "forever", now = new Date()) {
  const start = new Date(now);
  const end = new Date(now);

  switch (period) {
    case "hour":
      start.setUTCMinutes(0, 0, 0);
      end.setTime(start.getTime() + 3600_000);
      break;
    case "day":
      start.setUTCHours(0, 0, 0, 0);
      end.setUTCDate(start.getUTCDate() + 1);
      break;
    case "month":
      start.setUTCDate(1);
      start.setUTCHours(0, 0, 0, 0);
      end.setTime(start.getTime());
      end.setUTCMonth(start.getUTCMonth() + 1);
      break;
    case "forever":
    default:
      start.setTime(0);
      end.setUTCFullYear(9999, 11, 31);
      end.setUTCHours(23, 59, 59, 999);
      break;
  }

  return { start, end };
}

function scopeMaterial(constraint, context, payload, index, window) {
  const scope = constraint.scope || "credential";
  const material = {
    type: constraint.type,
    constraintId: constraint.id || sha256(stableStringify({ index, constraint })),
    scope,
    windowStart: window.start.toISOString(),
  };

  if (scope === "credential") {
    material.credentialId = payload.credentialId;
  } else if (scope === "agent") {
    material.agentId = payload.agentId;
    material.issuerId = payload.issuerId;
  } else if (scope === "issuer") {
    material.issuerId = payload.issuerId;
  } else if (scope === "resource") {
    material.agentId = payload.agentId;
    material.resource = context.resource;
  }

  for (const field of constraint.scopeFields || []) {
    material[`field:${field}`] = context[field];
  }

  return material;
}

async function readNumericField(field, context) {
  const resolved = await resolveSemanticField(field, context);
  if (!resolved.resolved) {
    return { ok: false, error: resolved.error, errorCode: resolved.errorCode || "context_field_missing" };
  }
  const value = Number(resolved.value);
  if (Number.isNaN(value)) {
    return { ok: false, error: `Field '${field}' is not numeric`, errorCode: "constraint_failed" };
  }
  return { ok: true, value };
}

async function buildCandidate(constraint, context, payload, index, now) {
  const period = constraint.period || "forever";
  const window = windowForPeriod(period, now);
  const material = scopeMaterial(constraint, context, payload, index, window);
  const counterKey = `stateful:${sha256(stableStringify(material))}`;

  if (constraint.type === "UsageLimitConstraint") {
    const limit = Number(constraint.maxUses ?? constraint.value ?? constraint.limit);
    if (!Number.isFinite(limit)) {
      return { ok: false, result: failureResult(constraint, "constraint_failed", "Usage limit is missing maxUses/value/limit") };
    }
    return {
      ok: true,
      candidate: {
        constraint,
        counterKey,
        windowStart: window.start,
        windowEnd: window.end,
        metric: "count",
        increment: 1,
        limit,
      },
    };
  }

  if (constraint.type === "CumulativeLimitConstraint") {
    const field = constraint.field;
    const limit = Number(constraint.maxAmount ?? constraint.value ?? constraint.limit);
    if (!field || !Number.isFinite(limit)) {
      return { ok: false, result: failureResult(constraint, "constraint_failed", "Cumulative limit is missing field or limit") };
    }

    const resolved = await readNumericField(field, context);
    if (!resolved.ok) {
      return { ok: false, result: failureResult(constraint, resolved.errorCode, resolved.error) };
    }

    return {
      ok: true,
      candidate: {
        constraint,
        counterKey,
        windowStart: window.start,
        windowEnd: window.end,
        metric: "amount",
        increment: resolved.value,
        limit,
      },
    };
  }

  return { ok: false, result: failureResult(constraint, "constraint_unknown", `Unknown stateful constraint: ${constraint.type}`) };
}

function failureResult(constraint, error, detail) {
  return {
    type: constraint.type,
    field: constraint.field || null,
    pass: false,
    error,
    detail,
  };
}

function passResult(candidate, current, next, idempotentReplay = false) {
  return {
    type: candidate.constraint.type,
    field: candidate.constraint.field || null,
    pass: true,
    expected: `<= ${candidate.limit}`,
    actual: next,
    detail: idempotentReplay ? "Idempotent replay; counter was not incremented again" : "Stateful limit satisfied",
    counterKey: candidate.counterKey,
  };
}

function denyResult(candidate, current, next) {
  return {
    type: candidate.constraint.type,
    field: candidate.constraint.field || null,
    pass: false,
    error: "stateful_limit_exceeded",
    expected: `<= ${candidate.limit}`,
    actual: next,
    detail: `Stateful limit exceeded: current ${current} + requested ${candidate.increment} > ${candidate.limit}`,
    counterKey: candidate.counterKey,
  };
}

export class MemoryStatefulStore {
  constructor() {
    this.counters = new Map();
    this.events = new Set();
  }

  async reserve(candidates, { idempotencyKey } = {}) {
    const results = [];
    const pending = [];

    for (const candidate of candidates) {
      const eventKey = idempotencyKey ? `${idempotencyKey}:${candidate.counterKey}` : null;
      const current = this.counters.get(candidate.counterKey) || 0;
      if (eventKey && this.events.has(eventKey)) {
        results.push(passResult(candidate, current, current, true));
        continue;
      }

      const next = current + candidate.increment;
      if (next > candidate.limit) {
        return { pass: false, results: [...results, denyResult(candidate, current, next)], error: "stateful_limit_exceeded" };
      }
      pending.push({ candidate, current, next, eventKey });
    }

    for (const item of pending) {
      this.counters.set(item.candidate.counterKey, item.next);
      if (item.eventKey) this.events.add(item.eventKey);
      results.push(passResult(item.candidate, item.current, item.next));
    }

    return { pass: true, results };
  }
}

class PostgresStatefulStore {
  constructor(pool) {
    this.pool = pool;
  }

  async reserve(candidates, { idempotencyKey, payload } = {}) {
    const client = await this.pool.connect();
    const results = [];

    try {
      await client.query("BEGIN");

      for (const candidate of candidates) {
        const eventKey = idempotencyKey ? `${idempotencyKey}:${candidate.counterKey}` : null;
        if (eventKey) {
          const { rows: eventRows } = await client.query(
            `SELECT 1 FROM portauth_authorization_counter_events
             WHERE idempotency_key = $1 AND counter_key = $2`,
            [idempotencyKey, candidate.counterKey]
          );
          if (eventRows.length > 0) {
            const { rows: counterRows } = await client.query(
              `SELECT used_amount, usage_count FROM portauth_authorization_counters WHERE counter_key = $1`,
              [candidate.counterKey]
            );
            const current = candidate.metric === "amount"
              ? Number(counterRows[0]?.used_amount || 0)
              : Number(counterRows[0]?.usage_count || 0);
            results.push(passResult(candidate, current, current, true));
            continue;
          }
        }

        await client.query(
          `INSERT INTO portauth_authorization_counters
             (counter_key, credential_id, agent_id, issuer_id, constraint_type,
              window_start, window_end, used_amount, usage_count)
           VALUES ($1,$2,$3,$4,$5,$6,$7,0,0)
           ON CONFLICT (counter_key) DO NOTHING`,
          [
            candidate.counterKey,
            payload?.credentialId || null,
            payload?.agentId || null,
            payload?.issuerId || null,
            candidate.constraint.type,
            candidate.windowStart,
            candidate.windowEnd,
          ]
        );

        const { rows } = await client.query(
          `SELECT used_amount, usage_count
           FROM portauth_authorization_counters
           WHERE counter_key = $1
           FOR UPDATE`,
          [candidate.counterKey]
        );
        const current = candidate.metric === "amount"
          ? Number(rows[0].used_amount)
          : Number(rows[0].usage_count);
        const next = current + candidate.increment;

        if (next > candidate.limit) {
          await client.query("ROLLBACK");
          return { pass: false, results: [...results, denyResult(candidate, current, next)], error: "stateful_limit_exceeded" };
        }

        await client.query(
          `UPDATE portauth_authorization_counters
           SET used_amount = used_amount + $2,
               usage_count = usage_count + $3,
               updated_at = NOW()
           WHERE counter_key = $1`,
          [
            candidate.counterKey,
            candidate.metric === "amount" ? candidate.increment : 0,
            candidate.metric === "count" ? candidate.increment : 0,
          ]
        );

        if (idempotencyKey) {
          await client.query(
            `INSERT INTO portauth_authorization_counter_events
               (idempotency_key, counter_key, credential_id, increment_amount)
             VALUES ($1,$2,$3,$4)
             ON CONFLICT DO NOTHING`,
            [idempotencyKey, candidate.counterKey, payload?.credentialId || null, candidate.increment]
          );
        }

        results.push(passResult(candidate, current, next));
      }

      await client.query("COMMIT");
      return { pass: true, results };
    } catch (err) {
      await client.query("ROLLBACK").catch(() => {});
      throw err;
    } finally {
      client.release();
    }
  }
}

export async function evaluateStatefulConstraints(constraints, context, payload, options = {}) {
  const now = options.now || new Date();
  const statefulConstraints = (constraints || [])
    .map((constraint, index) => ({ constraint, index }))
    .filter(({ constraint }) => isStatefulConstraint(constraint));

  if (statefulConstraints.length === 0) {
    return { pass: true, results: [], error: null };
  }

  const candidates = [];
  for (const { constraint, index } of statefulConstraints) {
    const built = await buildCandidate(constraint, context, payload, index, now);
    if (!built.ok) {
      return { pass: false, results: [built.result], error: built.result.error };
    }
    candidates.push(built.candidate);
  }

  // Plan 2: pre-check candidates whose constraint declares an external state
  // authority. The authority's signed counter value is the source of truth;
  // we deny here if accepting this request would exceed the limit, then fall
  // through to the local store for durability and idempotency.
  const fetchImpl = options.stateAuthorityFetch || globalThis.fetch;
  for (const candidate of candidates) {
    const auth = candidate.constraint.stateAuthority;
    if (!auth || !auth.authorityId) continue;
    const proof = await fetchCurrentValueFromAuthority({
      authorityId: auth.authorityId,
      counterKey: candidate.counterKey,
      windowStart: candidate.windowStart.toISOString(),
      maxAgeMs: auth.maxAgeMs ?? 30_000,
      fetchImpl,
    });
    if (!proof.ok) {
      return {
        pass: false,
        results: [failureResult(candidate.constraint, proof.errorCode, proof.error)],
        error: proof.errorCode,
      };
    }
    const next = proof.value + candidate.increment;
    if (next > candidate.limit) {
      return {
        pass: false,
        results: [denyResult(candidate, proof.value, next)],
        error: "stateful_limit_exceeded",
      };
    }
    candidate.authorityProof = proof;
  }

  const store = options.store || new PostgresStatefulStore(options.pool || getPool());
  const reservationResult = await store.reserve(candidates, {
    idempotencyKey: options.idempotencyKey || context.idempotencyKey || null,
    payload,
  });

  if (reservationResult.pass) {
    for (const candidate of candidates) {
      if (!candidate.authorityProof) continue;
      // Best-effort durability of consumed proofs
      await recordConsumedProof({
        authorityId: candidate.constraint.stateAuthority.authorityId,
        counterKey: candidate.counterKey,
        windowStart: candidate.windowStart.toISOString(),
        metric: candidate.metric,
        value: candidate.authorityProof.value,
        jws: candidate.authorityProof.jws,
        iat: candidate.authorityProof.proof.iat,
        requestId: context?.__request?.requestId || null,
      });
    }
  }

  return reservationResult;
}
